def handle_data(context, data):
    if not hasattr(context, 'prices'):
        context.prices = deque(maxlen=100)
    context.prices.append(data.current(context.asset, 'price'))

    if len(context.prices) > 100:
        signal = sum(list(context.prices)[-5:]) / 5
        order_target_percent(context.asset, signal)
